// ruleta3d.js - Modelo 3D Interactivo de la Ruleta de Cuadriculando en Three.js

(function () {
  let scene, camera, renderer, controls;
  let ruletaContainer;
  let wheelGroup;
  let autoRotate = true;
  let isSpinning = false;
  let spinVelocity = 0;
  let snapTarget = null;
  let snapProgress = 0;
  let lastTime = 0;

  const COLORS = {
    matteBlack: '#181a1b',
    slateBlue: '#2b3540',
    white: '#ffffff',
    sectorPurple: '#9c94c0',
    sectorGrey: '#eae8f1'
  };

  function init() {
    const container = document.getElementById('canvas-ruleta3d');
    if (!container) return;

    // 1. Escena
    scene = new THREE.Scene();

    // 2. Cámara (vista frontal en perspectiva)
    camera = new THREE.PerspectiveCamera(
      45,
      container.clientWidth / container.clientHeight,
      0.1,
      20
    );
    camera.position.set(0, 0, 2.5);

    // 3. Renderizador
    renderer = new THREE.WebGLRenderer({ antialias: true, alpha: true });
    renderer.setSize(container.clientWidth, container.clientHeight);
    renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
    renderer.shadowMap.enabled = true;
    renderer.shadowMap.type = THREE.PCFSoftShadowMap;
    renderer.physicallyCorrectLights = true;
    renderer.toneMapping = THREE.ACESFilmicToneMapping;
    renderer.toneMappingExposure = 1.15;
    container.appendChild(renderer.domElement);

    // 4. Controles
    controls = new THREE.OrbitControls(camera, renderer.domElement);
    controls.enableDamping = true;
    controls.dampingFactor = 0.05;
    controls.maxPolarAngle = Math.PI / 2 + 0.1;
    controls.minDistance = 1.0;
    controls.maxDistance = 5.0;
    controls.enabled = false; // Desactivados por defecto en la galería

    // 5. Luces
    const ambientLight = new THREE.AmbientLight(0xffffff, 0.6);
    scene.add(ambientLight);

    const dirLight1 = new THREE.DirectionalLight(0xffffff, 1.2);
    dirLight1.position.set(2, 4, 3);
    dirLight1.castShadow = true;
    dirLight1.shadow.mapSize.width = 1024;
    dirLight1.shadow.mapSize.height = 1024;
    dirLight1.shadow.bias = -0.0003;
    scene.add(dirLight1);

    const dirLight2 = new THREE.DirectionalLight(0xffffff, 0.8);
    dirLight2.position.set(-2, 2, -3);
    scene.add(dirLight2);

    // 6. Grupo principal
    ruletaContainer = new THREE.Group();
    ruletaContainer.position.set(0, -0.05, 0); // Centrar el modelo verticalmente
    scene.add(ruletaContainer);

    // 7. Construir ruleta
    buildRuleta();

    // 8. Raycaster para girar al hacer clic en el disco
    setupRaycaster();

    // 9. UI del lightbox
    setupUI();

    // 10. Animación
    lastTime = performance.now();
    animate();

    // 11. Redimensionado
    window.addEventListener('resize', onWindowResize, false);
  }

  const RULETA_IMAGE_BASE64 = 'data:image/png;base64,';

  function createWheelTexture() {
    const loader = new THREE.TextureLoader();
    const texture = loader.load(RULETA_IMAGE_BASE64, () => {
      if (renderer && scene && camera) {
        renderer.render(scene, camera);
      }
    });
    texture.wrapS = texture.wrapT = THREE.ClampToEdgeWrapping;
    texture.anisotropy = 4;
    return texture;
  }

  function buildRuleta() {
    const plateMaterial = new THREE.MeshStandardMaterial({
      color: new THREE.Color(COLORS.slateBlue),
      roughness: 0.85,
      metalness: 0.05
    });

    const darkMaterial = new THREE.MeshStandardMaterial({
      color: new THREE.Color(COLORS.matteBlack),
      roughness: 0.85,
      metalness: 0.08
    });

    // 1. Placa Base Cuadrada (MDF)
    const basePlate = new THREE.Mesh(new THREE.BoxGeometry(1.2, 1.2, 0.04), plateMaterial);
    basePlate.position.z = 0;
    basePlate.castShadow = true;
    basePlate.receiveShadow = true;
    ruletaContainer.add(basePlate);

    // 2. Mango superior con orificio rectangular y muesca indicadora triangular
    const handleShape = new THREE.Shape();
    // Silueta exterior del mango
    handleShape.moveTo(-0.15, 0.6);
    handleShape.lineTo(-0.15, 0.85);
    handleShape.lineTo(0.15, 0.85);
    handleShape.lineTo(0.15, 0.6);
    // Muesca triangular indicadora que apunta hacia abajo en el centro del mango
    handleShape.lineTo(0.04, 0.6);
    handleShape.lineTo(0, 0.54);
    handleShape.lineTo(-0.04, 0.6);
    handleShape.closePath();

    // Orificio interior del mango
    const holePath = new THREE.Path();
    holePath.moveTo(-0.10, 0.65);
    holePath.lineTo(-0.10, 0.80);
    holePath.lineTo(0.10, 0.80);
    holePath.lineTo(0.10, 0.65);
    holePath.closePath();
    handleShape.holes.push(holePath);

    const handleExtrudeSettings = { depth: 0.04, bevelEnabled: false };
    const handleGeo = new THREE.ExtrudeGeometry(handleShape, handleExtrudeSettings);
    const handleMesh = new THREE.Mesh(handleGeo, plateMaterial);
    handleMesh.position.z = -0.02; // Alinear con el espesor de la placa base
    handleMesh.castShadow = true;
    handleMesh.receiveShadow = true;
    ruletaContainer.add(handleMesh);

    // 3. Grupo del Disco Giratorio (para rotación de los números sobre el rodamiento)
    wheelGroup = new THREE.Group();
    wheelGroup.position.set(0, 0, 0.043); // Ajustado para un espesor de 5 mm (0.05 unidades)
    ruletaContainer.add(wheelGroup);

    // Disco de la Ruleta (Cilindro con textura de canvas)
    const wheelTex = createWheelTexture();
    const wheelFrontMat = new THREE.MeshStandardMaterial({
      map: wheelTex,
      roughness: 0.55,
      metalness: 0.08
    });

    const wheelMaterials = [
      darkMaterial,    // Lateral
      wheelFrontMat,   // Frente (+Y cara del cilindro)
      darkMaterial     // Dorso
    ];

    const wheelMesh = new THREE.Mesh(new THREE.CylinderGeometry(0.48, 0.48, 0.05, 64), wheelMaterials);
    wheelMesh.rotation.x = Math.PI / 2; // Girar para que apunte hacia el frente
    wheelMesh.position.set(0, 0, 0); // Posición local en el grupo giratorio
    wheelMesh.castShadow = true;
    wheelMesh.receiveShadow = true;
    wheelGroup.add(wheelMesh);

    // 4. Pin central negro (Eje fijo que no rota, tapando el rodamiento)
    const pinMesh = new THREE.Mesh(new THREE.CylinderGeometry(0.04, 0.04, 0.03, 32), darkMaterial);
    pinMesh.rotation.x = Math.PI / 2;
    pinMesh.position.set(0, 0, 0.08); // Ajustado para sobresalir por encima del disco de 5 mm
    pinMesh.castShadow = true;
    ruletaContainer.add(pinMesh);

    // 5. Plano de sombra de fondo
    const floorGeo = new THREE.PlaneGeometry(6, 6);
    const floorMat = new THREE.ShadowMaterial({ opacity: 0.3 });
    const floorMesh = new THREE.Mesh(floorGeo, floorMat);
    floorMesh.position.z = -0.1;
    floorMesh.receiveShadow = true;
    ruletaContainer.add(floorMesh);
  }

  function spin() {
    if (isSpinning) return;
    isSpinning = true;
    snapTarget = null;
    // Velocidad angular inicial aleatoria alta
    spinVelocity = 15.0 + Math.random() * 12.0;
  }

  function setupRaycaster() {
    const raycaster = new THREE.Raycaster();
    const mouse = new THREE.Vector2();

    const onClick = (event) => {
      const container = document.getElementById('canvas-ruleta3d');
      if (!container || !controls.enabled) return; // Solo interactivo en modo lightbox

      const rect = container.getBoundingClientRect();
      mouse.x = ((event.clientX - rect.left) / container.clientWidth) * 2 - 1;
      mouse.y = -((event.clientY - rect.top) / container.clientHeight) * 2 + 1;

      raycaster.setFromCamera(mouse, camera);

      // Detectar clic en el disco giratorio
      const intersects = raycaster.intersectObjects(wheelGroup.children, true);
      if (intersects.length > 0) {
        spin();
      }
    };

    const container = document.getElementById('canvas-ruleta3d');
    if (container) {
      container.addEventListener('pointerup', onClick);
    }
  }

  function setupUI() {
    const rotateBtn = document.getElementById('btn-ruleta3d-rotate');
    const topBtn = document.getElementById('btn-ruleta3d-top');
    const perspectiveBtn = document.getElementById('btn-ruleta3d-persp');
    const spinBtn = document.getElementById('btn-ruleta3d-spin');

    if (rotateBtn) {
      rotateBtn.addEventListener('click', () => {
        autoRotate = !autoRotate;
        rotateBtn.classList.toggle('is-active', autoRotate);
      });
    }

    if (topBtn) {
      topBtn.addEventListener('click', () => {
        autoRotate = false;
        if (rotateBtn) rotateBtn.classList.remove('is-active');
        animateCamera(0, 0, 2.2);
      });
    }

    if (perspectiveBtn) {
      perspectiveBtn.addEventListener('click', () => {
        autoRotate = false;
        if (rotateBtn) rotateBtn.classList.remove('is-active');
        animateCamera(1.2, 0.8, 1.8);
      });
    }

    if (spinBtn) {
      spinBtn.addEventListener('click', () => {
        spin();
      });
    }
  }

  let cameraAnim = {
    active: false,
    targetX: 0,
    targetY: 0,
    targetZ: 0,
    speed: 0.08
  };

  function animateCamera(x, y, z) {
    cameraAnim.targetX = x;
    cameraAnim.targetY = y;
    cameraAnim.targetZ = z;
    cameraAnim.active = true;
  }

  function animate() {
    requestAnimationFrame(animate);

    const now = performance.now();
    const dt = Math.min((now - lastTime) / 1000, 0.1); // limitar dt máximo para evitar saltos bruscos
    lastTime = now;

    if (autoRotate) {
      ruletaContainer.rotation.y += 0.003;
    }

    // Lógica física de giro de la ruleta (el disco con números)
    if (isSpinning) {
      wheelGroup.rotation.z += spinVelocity * dt;
      // Aplicar fricción exponencial
      spinVelocity *= Math.exp(-0.75 * dt);

      // Detener y pasar al snapping cuando baja la velocidad
      if (spinVelocity < 0.25) {
        isSpinning = false;
        
        // Encontrar el ángulo de snapping más cercano (múltiplo de Math.PI / 4)
        const currentRot = wheelGroup.rotation.z;
        let bestTarget = currentRot;
        let minDiff = Infinity;

        // Probar los 8 sectores y encontrar el k óptimo para cada uno
        for (let i = 0; i < 8; i++) {
          const baseAngle = i * Math.PI / 4;
          const k = Math.round((currentRot - baseAngle) / (Math.PI * 2));
          const candidate = baseAngle + k * Math.PI * 2;
          const diff = Math.abs(currentRot - candidate);
          if (diff < minDiff) {
            minDiff = diff;
            bestTarget = candidate;
          }
        }
        snapTarget = bestTarget;
        snapProgress = 0;
      }
    } else if (snapTarget !== null) {
      // Interpolar hacia el ángulo objetivo de snap
      snapProgress += dt * 4.0;
      if (snapProgress >= 1.0) {
        wheelGroup.rotation.z = snapTarget;
        snapTarget = null;
      } else {
        wheelGroup.rotation.z = THREE.MathUtils.lerp(wheelGroup.rotation.z, snapTarget, snapProgress);
      }
    }

    // Interpolar posicionamiento de cámara
    if (cameraAnim.active) {
      camera.position.x += (cameraAnim.targetX - camera.position.x) * cameraAnim.speed;
      camera.position.y += (cameraAnim.targetY - camera.position.y) * cameraAnim.speed;
      camera.position.z += (cameraAnim.targetZ - camera.position.z) * cameraAnim.speed;

      if (
        Math.abs(camera.position.x - cameraAnim.targetX) < 0.005 &&
        Math.abs(camera.position.y - cameraAnim.targetY) < 0.005 &&
        Math.abs(camera.position.z - cameraAnim.targetZ) < 0.005
      ) {
        camera.position.set(cameraAnim.targetX, cameraAnim.targetY, cameraAnim.targetZ);
        cameraAnim.active = false;
      }
    }

    controls.update();
    renderer.render(scene, camera);
  }

  function onWindowResize() {
    const container = document.getElementById('canvas-ruleta3d');
    if (!container) return;

    camera.aspect = container.clientWidth / container.clientHeight;
    camera.updateProjectionMatrix();
    renderer.setSize(container.clientWidth, container.clientHeight);
  }

  function checkAndInit() {
    if (typeof THREE !== 'undefined' && THREE.OrbitControls) init();
    else setTimeout(checkAndInit, 50);
  }

  // API pública del visor de la Ruleta
  window.Ruleta3D = {
    init: checkAndInit,
    setMode: function (isLarge) {
      controls.enabled = isLarge;
      autoRotate = !isLarge;
      
      const rotateBtn = document.getElementById('btn-ruleta3d-rotate');
      if (rotateBtn) {
        rotateBtn.classList.toggle('is-active', autoRotate);
      }

      // Resetear rotación, velocidad de giro y cámara al abrir o cerrar
      isSpinning = false;
      snapTarget = null;
      wheelGroup.rotation.z = 0;
      ruletaContainer.rotation.set(0, 0, 0);
      camera.position.set(0, 0, 2.5);
    },
    resize: function () {
      onWindowResize();
    }
  };
})();

